INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '908a3ccd-57c9-4609-a34f-ac5cba7491cb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery Dead Letter Queues — Poison Message Handling and Retry Backoff$escape$,
  $escape$Celery has no built-in dead-letter queue — you construct one via Kombu's `Queue` with `x-dead-letter-exchange` and `x-message-ttl` arguments on RabbitMQ. Without `task_acks_late = True` and `task_reject_on_worker_lost = True`, messages disappear silently on worker crashes instead of being requeued or dead-lettered. For poison message handling, `autoretry_for` drives retries automatically; pair it with `retry_backoff=2` (doubles each attempt), `retry_backoff_max=300` (caps at 5 minutes), and `retry_jitter=True` to scatter retry storms across workers. Once `max_retries` is exhausted, Celery raises `MaxRetriesExceededError` — override `on_failure` to capture the final exception and payload for manual inspection or re-routing. On RabbitMQ, messages that exceed TTL or are explicitly rejected flow to the configured DLX automatically, no extra code needed. Watch DLQ depth in Flower or via `celery inspect reserved`; a growing queue signals a deterministic bug in your task logic, not transient infrastructure noise.$escape$,
  $escape$from celery import Celery
from kombu import Queue

app = Celery('tasks')
app.conf.update(
    task_acks_late=True,
    task_reject_on_worker_lost=True,
    task_queues=[
        Queue('jobs', queue_arguments={'x-dead-letter-exchange': 'dlx', 'x-message-ttl': 60000}),
    ],
)

@app.task(bind=True, autoretry_for=(Exception,),
          retry_backoff=2, retry_backoff_max=300, retry_jitter=True, max_retries=5)
def process_event(self, payload: dict): ...$escape$,
