INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f2b00f37-823e-4d30-b365-abc915a051dd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery + Redis Cache — TTL, Eviction Policies, and Caching Strategies in Tasks$escape$,
  $escape$Celery uses Redis as both broker and result backend — but tasks often need Redis as a cache too. Mixing roles on one instance creates an eviction trap: `allkeys-lru` will evict task results under memory pressure, silently breaking `AsyncResult` state lookups. Use a dedicated Redis db (e.g., db=2 for cache) or switch to `volatile-lru` so only keys with explicit TTLs are evicted — Celery result keys carry TTLs via `result_expires` (default: 86400s).

Cache-aside is the safest pattern inside a Celery task: check Redis, on miss compute and write back with `ex=`. It keeps the task stateless and retryable. Write-through writes cache and DB atomically in the same task body — consistent but adds latency to every execution. Write-behind chains the DB write as a follow-up task via `.apply_async()`, cutting perceived latency but risking data loss if the worker crashes before the chain runs.

Set `result_expires` intentionally: short for fire-and-forget tasks, longer for polling flows using `AsyncResult.get()`. Never rely solely on eviction for cache invalidation — under peak load, evictions are non-deterministic.$escape$,
  $escape$import json
import redis
from celery import Celery

app = Celery("tasks", broker="redis://localhost:6379/0", backend="redis://localhost:6379/1")
app.conf.result_expires = 3600  # 1h TTL on task results

cache = redis.Redis(host="localhost", port=6379, db=2, decode_responses=True)

@app.task(bind=True, max_retries=3)
def get_user_stats(self, user_id: int) -> dict:
    key = f"user:stats:{user_id}"
    hit = cache.get(key)
    if hit:
        return json.loads(hit)
    stats = expensive_db_query(user_id)
    cache.set(key, json.dumps(stats), ex=300)  # 5-min TTL, cache-aside
    return stats$escape$,
  $escape$python$escape$,
