INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81833cdd-53de-4e05-b024-c5944a02e300',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery + RabbitMQ — Exchanges, Routing Keys, and Prefetch Done Right$escape$,
  $escape$Celery abstracts RabbitMQ's exchange model, but understanding it unlocks precise routing and backpressure control. By default, Celery uses a direct exchange — each queue binds to a routing key matching its name. You can override this with `task_queues` and `task_routes` to fan tasks across topic exchanges.

Acknowledgements matter: Celery sets `acks_late=False` by default, ACKing before the task runs. Flip to `acks_late=True` on your task (or globally via `task_acks_late`) so the message is only removed from RabbitMQ after successful execution — critical for idempotency.

Prefetch is where most teams get burned. Celery sets `worker_prefetch_multiplier=4`, meaning each worker prefills 4 × concurrency messages. For long-running tasks this starves other workers. Set it to `1` to enforce fair dispatch — each worker only takes a new message when it finishes the current one. Combine with `task_acks_on_failure_or_timeout=False` to guarantee requeue on crash.$escape$,
  $escape$# celeryconfig.py
from kombu import Exchange, Queue

task_queues = (
    Queue('default', Exchange('default', type='direct'), routing_key='default'),
    Queue('critical', Exchange('critical', type='direct'), routing_key='critical'),
)
task_default_queue = 'default'
task_default_exchange = 'default'
task_default_routing_key = 'default'

# Fair dispatch — one message per worker slot
worker_prefetch_multiplier = 1

# ACK only after task completes successfully
task_acks_late = True
task_acks_on_failure_or_timeout = False$escape$,
  $escape$python$escape$,
