INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5475ad11-fcdb-4f00-9326-b575dca53c15',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery — Task Routing, Beat, Result Backends, and Chaining in Production$escape$,
  $escape$Celery's routing system lets you direct tasks to specific queues using `task_routes` in your config. Define queues explicitly and bind workers to them with `-Q queue_name` — this keeps CPU-heavy tasks off your I/O queues. Celery Beat handles periodic tasks via `beat_schedule`, storing the schedule state in a database backend (use `django-celery-beat` for DB-backed schedules instead of the default file-based `shelve`). Result backends matter more than most teams realize: Redis is fast but volatile; use `result_expires` to avoid memory bloat. PostgreSQL via `django-celery-results` gives you durable, queryable results. Task chaining with `chain()` links tasks so each result feeds the next — combine with `group()` and `chord()` for fan-out/fan-in patterns. A `chord` executes a callback only after all grouped tasks complete, making it ideal for map-reduce workflows. Always set `task_acks_late=True` and `task_reject_on_worker_lost=True` together — without both, a worker crash silently drops in-flight tasks.$escape$,
  $escape$from celery import chain, group, chord
from myapp.celery import app

app.conf.update(
    task_routes={
        'myapp.tasks.render_video': {'queue': 'heavy'},
        'myapp.tasks.send_email': {'queue': 'io'},
    },
    task_acks_late=True,
    task_reject_on_worker_lost=True,
    result_expires=3600,
)

# Chain: compress → upload → notify
pipeline = chain(
    compress_file.s('input.mp4'),
    upload_to_cdn.s(),
    notify_user.s(user_id=42),
)
pipeline.delay()

# Chord: process N chunks, then aggregate
result = chord(
    group(process_chunk.s(chunk) for chunk in chunks)
)(aggregate_results.s())$escape$,
  $escape$python$escape$,
