INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '321e316f-05ac-4351-b576-1374f8adb768',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery + NATS JetStream — Subject Routing and At-Least-Once Delivery Without RabbitMQ$escape$,
  $escape$Celery's `task_routes` maps tasks to named queues; with RabbitMQ you get exchange/routing-key semantics, but maintaining that broker is operationally heavy. NATS JetStream replaces it with subject-based routing (`tasks.email.send`, `tasks.reports.*`) and durable, at-least-once delivery — no exchange configuration needed.

A JetStream stream bound to a subject wildcard (`tasks.>`) replaces your Celery queue declarations. Pull consumers mirror Celery's `--concurrency` workers: each consumer acks explicitly (`msg.ack()`), and unacked messages redeliver after the stream's `ack_wait` timeout — the same guarantee Celery achieves with `acks_late=True` on RabbitMQ.

Unlike Redis (where Celery uses BRPOP — the message is gone the moment a worker pops it), JetStream persists messages on disk and replays on worker crash. This makes NATS a natural upgrade when your Redis broker becomes a SPOF.

The catch: there's no production-grade Celery broker transport for NATS. You either wrap `nats-py` directly, dropping Celery's task DSL, or use the experimental `celery-nats` community package. Evaluate JetStream for greenfield services where NATS is already in your stack and subject-based fan-out beats Celery's queue-per-task routing.$escape$,
  $escape$import asyncio
import nats
from nats.js.api import StreamConfig

async def main():
    nc = await nats.connect("nats://localhost:4222")
    js = nc.jetstream()

    # Stream bound to wildcard — mirrors Celery queue declaration
    await js.add_stream(StreamConfig(name="TASKS", subjects=["tasks.>"]))

    # Publish — equivalent to send_email.apply_async(queue="email")
    await js.publish("tasks.email.send", b'{"user_id": 42}')

    # Pull consumer with explicit ack — mirrors Celery acks_late=True
    sub = await js.pull_subscribe("tasks.email.send", durable="email-worker")
    msgs = await sub.fetch(1, timeout=5)
    for msg in msgs:
        print(f"Processing: {msg.data}")
        await msg.ack()  # Redelivers after ack_wait if not acked

    await nc.close()

asyncio.run(main())$escape$,
  $escape$python$escape$,
