INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3beface7-9715-4418-b1ea-48f42cc56d3c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery Backpressure — Preventing Worker Memory Blowout When Consumers Lag$escape$,
  $escape$When Celery workers fall behind, brokers keep accepting tasks — your Redis or RabbitMQ queue grows unbounded while workers churn through a backlog, consuming increasing memory. Celery has no built-in backpressure, so you must engineer it explicitly.

The primary lever is `CELERYD_PREFETCH_MULTIPLIER`. It defaults to 4, meaning each worker prefetches 4× its concurrency count. A worker with 8 processes holds 32 tasks in memory simultaneously. Set it to 1 so each child process holds exactly one task — drastically reducing in-process queue depth.

Pair this with `worker_max_tasks_per_child` to reclaim memory after long-running tasks cause RSS bloat. For truly large payloads, avoid embedding data in task args — store in Redis/S3 and pass a key instead.

On the broker side, use RabbitMQ's `x-max-length` queue argument or Redis's `MAXMEMORY` + `noeviction` policy to reject tasks at source when the queue is full, forcing producers to slow down — actual backpressure at the protocol level.$escape$,
  $escape$# celeryconfig.py

# Each worker child holds exactly 1 task — minimizes prefetch memory
worker_prefetch_multiplier = 1

# Recycle worker after 500 tasks to prevent RSS memory creep
worker_max_tasks_per_child = 500

# Cap queue length in RabbitMQ (declare via Kombu)
from kombu import Queue

task_queues = (
    Queue(
        'default',
        queue_arguments={'x-max-length': 10000, 'x-overflow': 'reject-publish'}
    ),
)

# Producer now gets a 'basic.nack' when queue is full — backpressure achieved$escape$,
  $escape$python$escape$,
