INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '666d17da-c85d-4f35-8f65-a48785dcd153',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery — Scaling Workers Horizontally Without Dropping Tasks$escape$,
  $escape$Celery scales horizontally by running multiple worker processes, each consuming from the same broker queue. The critical knob is `--concurrency`, which controls the number of child processes (or threads/coroutines) per worker. By default it matches CPU count — fine for CPU-bound tasks, wrong for I/O-bound ones where you want higher concurrency via `--pool=gevent` or `--pool=eventlet`.

With Redis as broker, all workers compete on the same list key — no concept of partitions. With RabbitMQ, you can use `x-max-priority` or separate named queues to control routing. With Kafka via `celery-kafka` or Confluent backends, partition count directly limits parallelism: more partitions = more workers can consume independently without stepping on each other.

Rebalancing in Celery is implicit — workers just stop polling when shut down. Use `--max-tasks-per-child` to recycle workers that leak memory. For graceful scaling, send `SIGTERM` and let in-flight tasks finish (`--without-gossip --without-mingle` reduces overhead in large fleets). Use `celery inspect active` to confirm drain before terminating.$escape$,
  $escape$# Launch workers targeting specific queues with tuned concurrency
# High-throughput I/O queue: gevent pool, high concurrency
celery -A myapp worker -Q io_tasks --pool=gevent --concurrency=500 --loglevel=info &

# CPU-bound queue: prefork pool, one worker per core
celery -A myapp worker -Q cpu_tasks --pool=prefork --concurrency=8 --max-tasks-per-child=100 &

# Inspect active tasks across all workers before scaling down
celery -A myapp inspect active

# Graceful shutdown — waits for in-flight tasks
celery -A myapp control shutdown$escape$,
  $escape$bash$escape$,
