INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '81e98fd1-5c05-4834-88ec-fb700151ff73',
  '00000000-0000-0000-0000-000000000001',
  $escape$Celery Monitoring — Queue Depth, Consumer Lag, and Dead Letter Alerts$escape$,
  $escape$Celery exposes queue depth via the broker backend. With Redis, `app.control.inspect().active()` and `app.control.inspect().reserved()` reveal in-flight and queued tasks per worker, but for raw queue depth you query Redis directly: `redis_client.llen('celery')`. Consumer lag emerges when producers outpace workers — track it by comparing enqueue rate against `inspect().stats()['total']` throughput over time.

For dead letter queues, Celery doesn't natively route failed tasks to a DLQ, but you can simulate one using `task_acks_late = True` combined with a custom `on_failure` handler or `after_return` signal that re-publishes to a `celery.dead` queue. Alternatively, configure Kombu's dead-letter exchange directly on the broker queue declaration.

For alerting, instrument `task_failure` and `task_retry` signals with counters pushed to Prometheus via `prometheus_client`. Set alert rules: queue depth > 500 for 5 minutes, retry rate > 10/min, or any task landing in `celery.dead`. Use Flower's REST API (`/api/queues/length`) for a quick dashboard integration without custom instrumentation.$escape$,
  $escape$from celery.signals import task_failure, task_retry
from prometheus_client import Counter

TASK_FAILURES = Counter('celery_task_failures_total', 'Total task failures', ['task_name'])
TASK_RETRIES = Counter('celery_task_retries_total', 'Total task retries', ['task_name'])

@task_failure.connect
def on_task_failure(sender=None, task_id=None, exception=None, **kwargs):
    TASK_FAILURES.labels(task_name=sender.name).inc()

@task_retry.connect
def on_task_retry(sender=None, reason=None, **kwargs):
    TASK_RETRIES.labels(task_name=sender.name).inc()

# Queue depth check via Redis
import redis
r = redis.Redis()
depth = r.llen('celery')  # alert if depth > threshold$escape$,
  $escape$python$escape$,
